class Solution(object):
    def isSubtree(self, root, subRoot):
        def is_same(p, q):
            if not p and not q:
                return True
            if not p or not q:
                return False
            return p.val == q.val and is_same(p.left, q.left) and is_same(p.right, q.right)
        def dfs(node):
            if not node:
                return False
            return is_same(node, subRoot) or dfs(node.left) or dfs(node.right)
        return dfs(root)
